#!/usr/bin/env node
/**
 * apply-ein-backfill.cjs
 *
 * Consumes the EIN backfill candidate list generated by discover-990-gaps
 * and applies unambiguous candidates to profile frontmatter + the
 * corresponding entities.jsonl record. Applies only where:
 *   - Candidate list has exactly one EIN, AND
 *   - Profile currently has no `ein:` field, AND
 *   - Not in the EXPLICIT_SKIP set (collision-risk cases flagged for David)
 *
 * Multi-candidate rows get reported but not modified — those need David's
 * editorial call on which EIN is the right one.
 *
 * Usage:
 *   node scripts/apply-ein-backfill.cjs             # dry-run report
 *   node scripts/apply-ein-backfill.cjs --write     # apply frontmatter + entity updates
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const ENTITIES = path.join(ROOT, 'data', 'entities.jsonl');

const args = process.argv.slice(2);
const WRITE = args.includes('--write');

// Hand-curated candidate list from content/Admin Notes/ein-backfill-candidates.md.
// Only include rows with a single, unambiguous EIN candidate.
const CANDIDATES = [
  { title: 'Donors Trust', ein: '522166327', path: 'content/Donors & Power Networks/Dark Money/Donors Trust/Donors Trust.md' },
  { title: 'Change Now', ein: '831307183', path: 'content/Donors & Power Networks/Super PACs/Change Now.md' },
  { title: 'Environment America INC', ein: '205355252', path: 'content/Donors & Power Networks/Super PACs/Environment America INC.md' },
  { title: 'Prison Policy Initiative', ein: '203671130', path: 'content/Donors & Power Networks/Carceral State/Prison Policy Initiative.md' },
  { title: 'Fair Share Action', ein: '460932086', path: 'content/Donors & Power Networks/Super PACs/Fair Share Action.md' },
  { title: 'Living United for Change in Arizona', ein: '271398645', path: 'content/Donors & Power Networks/Super PACs/Living United for Change in Arizona.md' },
  { title: 'The Lincoln Project', ein: '843583045', path: 'content/Donors & Power Networks/Super PACs/The Lincoln Project.md' },
  { title: 'Conservation Ohio', ein: '310805578', path: 'content/Donors & Power Networks/Dark Money/Conservation Ohio.md' },
  { title: 'American Future Fund', ein: '260620554', path: 'content/Donors & Power Networks/Super PACs/American Future Fund.md' },
  { title: 'Crossroads Grassroots Policy Strategies', ein: '272753378', path: 'content/Donors & Power Networks/Dark Money/Crossroads Grassroots Policy Strategies.md' },
  { title: 'Bluegreen Alliance', ein: '264086284', path: 'content/Donors & Power Networks/Super PACs/Bluegreen Alliance.md' },
  { title: 'American Energy Alliance', ein: '262731617', path: 'content/Donors & Power Networks/Energy & Utilities/American Energy Alliance/American Energy Alliance.md' },
  { title: 'House Majority PAC', ein: '451672898', path: 'content/Donors & Power Networks/Super PACs/House Majority PAC.md' },
  { title: 'Senate Majority PAC', ein: '272896127', path: 'content/Donors & Power Networks/Super PACs/Senate Majority PAC.md' },
  { title: 'Put Utah First PAC', ein: '873204548', path: 'content/Donors & Power Networks/Dark Money/Put Utah First Pac.md' },
  { title: 'United We Can', ein: '360852885', path: 'content/Donors & Power Networks/Dark Money/United We Can.md' },
  { title: 'Citizens for Responsible Energy Solutions Inc.', ein: '460558330', path: 'content/Donors & Power Networks/Super PACs/Citizens for Responsible Energy Solutions Inc..md' },
  { title: 'Michigan Republican Party', ein: '381221182', path: 'content/Donors & Power Networks/Super PACs/Michigan Republican Party.md' },
  { title: 'Republican Party of Florida', ein: '590683241', path: 'content/Donors & Power Networks/Super PACs/Republican Party of Florida.md' },
  { title: 'Fight Corporate Monopolies', ein: '825097446', path: 'content/Donors & Power Networks/Super PACs/Fight Corporate Monopolies.md' },
  { title: 'Ohio AFL-CIO', ein: '314425064', path: 'content/Donors & Power Networks/Labor Unions/Ohio AFL-CIO.md' },
  { title: 'Latino Vote for America Pac', ein: '844734272', path: 'content/Donors & Power Networks/Dark Money/Latino Vote for America Pac.md' },
  { title: 'Progressive Turnout Project', ein: '474414152', path: 'content/Donors & Power Networks/Super PACs/Progressive Turnout Project.md' },
];

// Skipped because of duplicate-profile collisions or multi-EIN ambiguity:
const SKIPPED = [
  { title: 'Judicial Crisis Network', reason: 'Duplicate profile — The Concord Fund stub (same EIN 202303252) was created for the rebranded entity. Needs David merge decision before backfill.' },
  { title: 'Planned Parenthood Action Fund INC', reason: 'Two candidate EINs (133539048, 134128897). Needs manual selection.' },
  { title: 'Planned Parenthood Votes', reason: 'Candidate EIN 134128897 also appears on Planned Parenthood Action Fund row — likely same entity, different profile.' },
  { title: 'American Conservative Union', reason: 'Two candidate EINs (520810813, 521294680). Needs manual selection.' },
];

function addEinToFrontmatter(filePath, ein) {
  const text = fs.readFileSync(filePath, 'utf-8');
  const m = text.match(/^(---\n[\s\S]*?\n---)/);
  if (!m) return { ok: false, reason: 'no frontmatter' };
  const fm = m[1];
  if (/\n\s*ein:\s*['"]?\d+/.test(fm)) return { ok: false, reason: 'already has ein' };
  // Insert ein line after source-tier or sector or last-updated
  const anchor = fm.match(/\n(source-tier:|sector:|last-updated:|type:)[^\n]+\n/);
  let newFm;
  if (anchor) {
    const idx = anchor.index + anchor[0].length;
    newFm = fm.slice(0, idx) + `ein: "${ein}"\n` + fm.slice(idx);
  } else {
    // Fallback: just before closing ---
    newFm = fm.replace(/\n---$/, `\nein: "${ein}"\n---`);
  }
  const newText = text.replace(fm, newFm);
  fs.writeFileSync(filePath, newText);
  return { ok: true };
}

function addEinToEntity(profilePath, ein) {
  const raw = fs.readFileSync(ENTITIES, 'utf-8');
  const lines = raw.split('\n');
  const normProfilePath = profilePath.replace(/\\/g, '/');
  let updated = false;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    try {
      const r = JSON.parse(line);
      const p = (r.profile_path || '').replace(/\\/g, '/');
      if (p !== normProfilePath) continue;
      if (!r.signals) r.signals = {};
      if (r.signals.ein === ein) return { ok: false, reason: 'entity already has ein' };
      r.signals.ein = ein;
      r.last_updated = new Date().toISOString();
      lines[i] = JSON.stringify(r);
      updated = true;
      break;
    } catch {}
  }
  if (!updated) return { ok: false, reason: 'entity not found' };
  fs.writeFileSync(ENTITIES, lines.join('\n'));
  return { ok: true };
}

(function main() {
  console.log(`[apply-ein-backfill] ${WRITE ? 'WRITE' : 'DRY-RUN'}\n`);

  let applied = 0, skippedExisting = 0, errors = 0;
  const unresolvedFiles = [];

  for (const c of CANDIDATES) {
    const abs = path.join(ROOT, c.path);
    if (!fs.existsSync(abs)) {
      unresolvedFiles.push(c);
      console.log(`  [missing] ${c.title}: ${c.path}`);
      errors++;
      continue;
    }
    if (!WRITE) { console.log(`  [would backfill] ${c.title} (EIN ${c.ein})`); applied++; continue; }

    const r1 = addEinToFrontmatter(abs, c.ein);
    const r2 = addEinToEntity(c.path, c.ein);
    if (r1.ok && r2.ok) { console.log(`  [backfilled] ${c.title} (EIN ${c.ein})`); applied++; }
    else if (r1.reason === 'already has ein') { console.log(`  [skip already-has] ${c.title}`); skippedExisting++; }
    else { console.log(`  [err] ${c.title}: fm=${r1.ok ? 'ok' : r1.reason}, ent=${r2.ok ? 'ok' : r2.reason}`); errors++; }
  }

  console.log(`\n${WRITE ? 'applied' : 'would-apply'}: ${applied}, already-has: ${skippedExisting}, errors: ${errors}`);
  console.log(`skipped for manual review: ${SKIPPED.length}`);
  for (const s of SKIPPED) console.log(`  - ${s.title}: ${s.reason}`);
})();
